package com.google.gson;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.math.BigDecimal;
import java.math.BigInteger;

import static org.junit.jupiter.api.Assertions.assertThrows;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class JsonElementTest {

  @Test
  public void testGetAsInt_throwsUnsupportedOperationException() throws Exception {
    // Create anonymous subclass instance since JsonElement is abstract
    JsonElement element = new JsonElement() {
      @Override
      public JsonElement deepCopy() {
        return this;
      }
    };

    // Use reflection to invoke getAsInt()
    Method getAsIntMethod = JsonElement.class.getDeclaredMethod("getAsInt");
    getAsIntMethod.setAccessible(true);

    UnsupportedOperationException thrown = assertThrows(UnsupportedOperationException.class, () -> {
      getAsIntMethod.invoke(element);
    });

    // Assert the exception message is the simple class name
    assert(thrown.getMessage().equals("JsonElement"));
  }
}
